-- SQL Island: The Escape Protocol -- Database setup for Eskuel Mission 1
CREATE TABLE players ( id INTEGER, name TEXT, level INTEGER, inventory TEXT[] );
INSERT INTO players VALUES (1, 'Aria', 12, ARRAY['engine_part','fuel_cell','toolkit']), (2, 'Borin', 9, ARRAY['navigation_chip','fuel_cell']), (3, 'Ciri', 15, ARRAY['repair_kit','oxygen_tank','toolkit']), (4, 'Darius', 7, ARRAY['oxygen_tank','fuel_cell']), (5, 'Lyra', 20, ARRAY['database_key','navigation_chip','repair_kit']);
